    44→export type MailboxDetail = {
    45→	mailbox: MailBox
    46→	folders: FolderSystem
    47→	mailGroupInfo: GroupInfo
    48→	mailGroup: Group
    49→	mailboxGroupRoot: MailboxGroupRoot
    50→}
    51→
    52→export type MailboxCounters = Record<Id, Record<string, number>>
    53→
    54→export class MailModel {
    55→	/** Empty stream until init() is finished, exposed mostly for map()-ing, use getMailboxDetails to get a promise */
    56→	readonly mailboxDetails: Stream<MailboxDetail[]> = stream()
    57→	readonly mailboxCounters: Stream<MailboxCounters> = stream({})
    58→	private initialization: Promise<void> | null = null
    59→	/**
    60→	 * Map from MailboxGroupRoot id to MailboxProperties
    61→	 * A way to avoid race conditions in case we try to create mailbox properties from multiple places.
    62→	 *
    63→	 */
    64→	private mailboxPropertiesPromises: Map<Id, Promise<MailboxProperties>> = new Map()
    65→
    66→	constructor(
    67→		private readonly notifications: Notifications,
    68→		private readonly eventController: EventController,
    69→		private readonly connectivityModel: WebsocketConnectivityModel,
    70→		private readonly mailFacade: MailFacade,
    71→		private readonly entityClient: EntityClient,
    72→		private readonly logins: LoginController,
    73→		private readonly inboxRuleHandler: InboxRuleHandler,
    74→	) {}
    75→
    76→	// only init listeners once
    77→	private readonly initListeners = lazyMemoized(() => {
    78→		this.eventController.addEntityListener((updates) => this.entityEventsReceived(updates))
    79→
    80→		this.eventController.getCountersStream().map((update) => {
    81→			this._mailboxCountersUpdates(update)
    82→		})
    83→	})
    84→
    85→	init(): Promise<void> {
    86→		// if we are in the process of loading do not start another one in parallel
    87→		if (this.initialization) {
    88→			return this.initialization
    89→		}
    90→		this.initListeners()
    91→
    92→		return this._init()
    93→	}
    94→
    95→	private _init(): Promise<void> {
    96→		const mailGroupMemberships = this.logins.getUserController().getMailGroupMemberships()
    97→		const mailBoxDetailsPromises = mailGroupMemberships.map((m) => this.mailboxDetailsFromMembership(m))
    98→		this.initialization = Promise.all(mailBoxDetailsPromises).then((details) => {
    99→			this.mailboxDetails(details)
   100→		})
   101→		return this.initialization.catch((e) => {
   102→			console.warn("mail model initialization failed!", e)
   103→			this.initialization = null
   104→			throw e
   105→		})
   106→	}
   107→
   108→	/**
   109→	 * load mailbox details from a mailgroup membership
   110→	 */
   111→	private async mailboxDetailsFromMembership(membership: GroupMembership): Promise<MailboxDetail> {
   112→		const [mailboxGroupRoot, mailGroupInfo, mailGroup] = await Promise.all([
   113→			this.entityClient.load(MailboxGroupRootTypeRef, membership.group),
   114→			this.entityClient.load(GroupInfoTypeRef, membership.groupInfo),
   115→			this.entityClient.load(GroupTypeRef, membership.group),
   116→		])
   117→		const mailbox = await this.entityClient.load(MailBoxTypeRef, mailboxGroupRoot.mailbox)
   118→		const folders = await this.loadFolders(neverNull(mailbox.folders).folders)
   119→		return {
   120→			mailbox,
   121→			folders: new FolderSystem(folders),
   122→			mailGroupInfo,
   123→			mailGroup,
   124→			mailboxGroupRoot,
   125→		}
   126→	}
   127→
   128→	private loadFolders(folderListId: Id): Promise<MailFolder[]> {
   129→		return this.entityClient.loadAll(MailFolderTypeRef, folderListId).then((folders) => {
   130→			return folders.filter((f) => {
   131→				// We do not show spam or archive for external users
   132→				if (!this.logins.isInternalUserLoggedIn() && (f.folderType === MailFolderType.SPAM || f.folderType === MailFolderType.ARCHIVE)) {
   133→					return false
   134→				} else if (this.logins.isEnabled(FeatureType.InternalCommunication) && f.folderType === MailFolderType.SPAM) {
   135→					return false
   136→				} else {
   137→					return true
   138→				}
   139→			})
   140→		})
   141→	}
   142→
   143→	/**
   144→	 * Get the list of MailboxDetails that this user has access to from their memberships.
   145→	 *
   146→	 * Will wait for successful initialization.
   147→	 */
   148→	async getMailboxDetails(): Promise<Array<MailboxDetail>> {
   149→		// If details are there, use them
   150→		if (this.mailboxDetails()) {
   151→			return this.mailboxDetails()
   152→		} else {
   153→			// If they are not there, trigger loading again (just in case) but do not fail and wait until we actually have the details.
   154→			// This is so that the rest of the app is not in the broken state if details fail to load but is just waiting until the success.
   155→			return new Promise((resolve) => {
   156→				this.init()
   157→				const end = this.mailboxDetails.map((details) => {
   158→					resolve(details)
   159→					end.end(true)
   160→				})
   161→			})
   162→		}
   163→	}
   164→
   165→	getMailboxDetailsForMail(mail: Mail): Promise<MailboxDetail | null> {
   166→		return this.getMailboxDetailsForMailListId(mail._id[0])
   167→	}
   168→
   169→	async getMailboxDetailsForMailListId(mailListId: Id): Promise<MailboxDetail | null> {
   170→		const mailboxDetails = await this.getMailboxDetails()
   171→		const detail = mailboxDetails.find((md) => md.folders.getFolderByMailListId(mailListId)) ?? null
   172→		if (detail == null) {
   173→			console.warn("Mailbox detail for mail list does not exist", mailListId)
   174→		}
   175→		return detail
   176→	}
   177→
   178→	async getMailboxDetailsForMailGroup(mailGroupId: Id): Promise<MailboxDetail> {
   179→		const mailboxDetails = await this.getMailboxDetails()
   180→		return assertNotNull(
   181→			mailboxDetails.find((md) => mailGroupId === md.mailGroup._id),
   182→			"No mailbox details for mail group",
   183→		)
   184→	}
   185→
   186→	async getUserMailboxDetails(): Promise<MailboxDetail> {
   187→		const userMailGroupMembership = this.logins.getUserController().getUserMailGroupMembership()
   188→		const mailboxDetails = await this.getMailboxDetails()
   189→		return assertNotNull(mailboxDetails.find((md) => md.mailGroup._id === userMailGroupMembership.group))
   190→	}
   191→
   192→	getMailboxFolders(mail: Mail): Promise<FolderSystem | null> {
   193→		return this.getMailboxDetailsForMail(mail).then((md) => md && md.folders)
   194→	}
   195→
   196→	getMailFolder(mailListId: Id): MailFolder | null {
   197→		const mailboxDetails = this.mailboxDetails() || []
   198→
   199→		for (let detail of mailboxDetails) {
   200→			const f = detail.folders.getFolderByMailListId(mailListId)
   201→			if (f) {
   202→				return f
   203→			}
   204→		}
   205→
   206→		return null
   207→	}
   208→
   209→	/**
   210→	 * Sends the given folder and all its descendants to the spam folder, reporting mails (if applicable) and removes any empty folders
   211→	 */
   212→	async sendFolderToSpam(folder: MailFolder): Promise<void> {
   213→		const mailboxDetail = await this.getMailboxDetailsForMailListId(folder.mails)
   214→		if (mailboxDetail == null) {
   215→			return
   216→		}
   217→
   218→		let deletedFolder = await this.removeAllEmpty(mailboxDetail, folder)
   219→		if (!deletedFolder) {
   220→			return this.mailFacade.updateMailFolderParent(folder, assertSystemFolderOfType(mailboxDetail.folders, MailFolderType.SPAM)._id)
   221→		}
   222→	}
   223→
   224→	async reportMails(reportType: MailReportType, mails: ReadonlyArray<Mail>): Promise<void> {
   225→		for (const mail of mails) {
   226→			await this.mailFacade.reportMail(mail, reportType).catch(ofClass(NotFoundError, (e) => console.log("mail to be reported not found", e)))
   227→		}
   228→	}
   229→
   230→	/**
   231→	 * Finally deletes all given mails. Caller must ensure that mails are only from one folder
   232→	 */
   233→	async _moveMails(mails: Mail[], targetMailFolder: MailFolder): Promise<void> {
   234→		let moveMails = mails.filter(
   235→			(m) =>
   236→				m._id[0] !== targetMailFolder.mails &&
   237→				targetMailFolder._ownerGroup === m._ownerGroup &&
   238→				// there is a chance to get here without going through that check when using multiselect, so checking again here.
   239→				!areParticipantsRestricted(m),
   240→		) // prevent moving mails between mail boxes.
   241→
   242→		// Do not move if target is the same as the current mailFolder
   243→		const sourceMailFolder = this.getMailFolder(getListId(mails[0]))
   244→
   245→		if (moveMails.length > 0 && sourceMailFolder && !isSameId(targetMailFolder._id, sourceMailFolder._id)) {
   246→			const mailChunks = splitInChunks(
   247→				MAX_NBR_MOVE_DELETE_MAIL_SERVICE,
   248→				mails.map((m) => m._id),
   249→			)
   250→
   251→			for (const mailChunk of mailChunks) {
   252→				await this.mailFacade.moveMails(mailChunk, targetMailFolder._id)
   253→			}
   254→		}
   255→	}
   256→
   257→	/**
   258→	 * Preferably use moveMails() in MailGuiUtils.js which has built-in error handling
   259→	 * @throws PreconditionFailedError or LockedError if operation is locked on the server
   260→	 */
   261→	async moveMails(mails: ReadonlyArray<Mail>, targetMailFolder: MailFolder): Promise<void> {
   262→		const mailsPerFolder = groupBy(mails, (mail) => {
   263→			return getListId(mail)
   264→		})
   265→
   266→		for (const [listId, mails] of mailsPerFolder) {
   267→			const sourceMailFolder = this.getMailFolder(listId)
   268→
   269→			if (sourceMailFolder) {
   270→				await this._moveMails(mails, targetMailFolder)
   271→			} else {
   272→				console.log("Move mail: no mail folder for list id", listId)
   273→			}
   274→		}
   275→	}
   276→
   277→	isMovingMailsAllowed(): boolean {
   278→		return this.logins.getUserController().isInternalUser()
   279→	}
   280→
   281→	isExportingMailsAllowed(): boolean {
   282→		return !this.logins.isEnabled(FeatureType.DisableMailExport)
   283→	}
   284→
   285→	async markMails(mails: readonly Mail[], unread: boolean): Promise<void> {
   286→		await promiseMap(
   287→			mails,
   288→			async (mail) => {
   289→				if (mail.unread !== unread) {
   290→					mail.unread = unread
   291→					return this.entityClient.update(mail).catch(ofClass(NotFoundError, noOp)).catch(ofClass(LockedError, noOp))
   292→				}
   293→			},
   294→			{ concurrency: 5 },
   295→		)
   296→	}
   297→
   298→	/**
   299→	 * Finally deletes the given mails if they are already in the trash or spam folders,
   300→	 * otherwise moves them to the trash folder.
   301→	 * A deletion confirmation must have been show before.
   302→	 */
   303→	async deleteMails(mails: ReadonlyArray<Mail>): Promise<void> {
   304→		const mailsPerFolder = groupBy(mails, (mail) => {
   305→			return getListId(mail)
   306→		})
   307→
   308→		if (mails.length === 0) {
   309→			return
   310→		}
   311→		const folders = await this.getMailboxFolders(mails[0])
   312→		if (folders == null) {
   313→			return
   314→		}
   315→		const trashFolder = assertNotNull(folders.getSystemFolderByType(MailFolderType.TRASH))
   316→
   317→		for (const [listId, mails] of mailsPerFolder) {
   318→			const sourceMailFolder = this.getMailFolder(listId)
   319→
   320→			if (sourceMailFolder) {
   321→				if (isSpamOrTrashFolder(folders, sourceMailFolder)) {
   322→					await this._finallyDeleteMails(mails)
   323→				} else {
   324→					await this._moveMails(mails, trashFolder)
   325→				}
   326→			} else {
   327→				console.log("Delete mail: no mail folder for list id", listId)
   328→			}
   329→		}
   330→	}
   331→
   332→	/**
   333→	 * Finally deletes all given mails. Caller must ensure that mails are only from one folder and the folder must allow final delete operation.
   334→	 */
   335→	async _finallyDeleteMails(mails: Mail[]): Promise<void> {
   336→		if (!mails.length) return Promise.resolve()
   337→		const mailFolder = neverNull(this.getMailFolder(getListId(mails[0])))
   338→		const mailIds = mails.map((m) => m._id)
   339→		const mailChunks = splitInChunks(MAX_NBR_MOVE_DELETE_MAIL_SERVICE, mailIds)
   340→
   341→		for (const mailChunk of mailChunks) {
   342→			await this.mailFacade.deleteMails(mailChunk, mailFolder._id)
   343→		}
   344→	}
   345→
   346→	async entityEventsReceived(updates: ReadonlyArray<EntityUpdateData>): Promise<void> {
   347→		for (const update of updates) {
   348→			if (isUpdateForTypeRef(MailFolderTypeRef, update)) {
   349→				await this._init()
   350→				m.redraw()
   351→			} else if (isUpdateForTypeRef(GroupInfoTypeRef, update)) {
   352→				if (update.operation === OperationType.UPDATE) {
   353→					await this._init()
   354→					m.redraw
   355→				}
   356→			} else if (isUpdateForTypeRef(UserTypeRef, update)) {
   357→				if (update.operation === OperationType.UPDATE && isSameId(this.logins.getUserController().user._id, update.instanceId)) {
   358→					const updatedUser = await this.entityClient.load(UserTypeRef, update.instanceId)
   359→					let newMemberships = updatedUser.memberships.filter((membership) => membership.groupType === GroupType.Mail)
   360→					const mailboxDetails = await this.getMailboxDetails()
   361→
   362→					if (newMemberships.length !== mailboxDetails.length) {
   363→						await this._init()
   364→						m.redraw()
   365→					}
   366→				}
   367→			} else if (isUpdateForTypeRef(MailTypeRef, update) && update.operation === OperationType.CREATE) {
   368→				const folder = this.getMailFolder(update.instanceListId)
   369→
   370→				if (folder && folder.folderType === MailFolderType.INBOX && !containsEventOfType(updates, OperationType.DELETE, update.instanceId)) {
   371→					// If we don't find another delete operation on this email in the batch, then it should be a create operation,
   372→					// otherwise it's a move
   373→					const mailId: IdTuple = [update.instanceListId, update.instanceId]
   374→					const mail = await this.entityClient.load(MailTypeRef, mailId)
   375→					await this.getMailboxDetailsForMailListId(update.instanceListId)
   376→						.then((mailboxDetail) => {
   377→							// We only apply rules on server if we are the leader in case of incoming messages
   378→							return mailboxDetail && this.inboxRuleHandler.findAndApplyMatchingRule(mailboxDetail, mail, this.connectivityModel.isLeader())
   379→						})
   380→						.then((newId) => this._showNotification(newId || mailId))
   381→						.catch(noOp)
   382→				}
   383→			}
   384→		}
   385→	}
   386→
   387→	_mailboxCountersUpdates(counters: WebsocketCounterData) {
   388→		const normalized = this.mailboxCounters() || {}
   389→		const group = normalized[counters.mailGroup] || {}
   390→		counters.counterValues.forEach((value) => {
   391→			group[value.mailListId] = Number(value.count) || 0
   392→		})
   393→		normalized[counters.mailGroup] = group
   394→		this.mailboxCounters(normalized)
   395→	}
   396→
   397→	_showNotification(mailId: IdTuple) {
   398→		this.notifications.showNotification(
   399→			lang.get("newMails_msg"),
   400→			{
   401→				actions: [],
   402→			},
   403→			(_) => {
   404→				m.route.set(`/mail/${listIdPart(mailId)}/${elementIdPart(mailId)}`)
   405→				window.focus()
   406→			},
   407→		)
   408→	}
   409→
   410→	getCounterValue(listId: Id): Promise<number | null> {
   411→		return this.getMailboxDetailsForMailListId(listId)
   412→			.then((mailboxDetails) => {
   413→				if (mailboxDetails == null) {
   414→					return null
   415→				} else {
   416→					const counters = this.mailboxCounters()
   417→					const mailGroupCounter = counters[mailboxDetails.mailGroup._id]
   418→					return mailGroupCounter && mailGroupCounter[listId]
   419→				}
   420→			})
   421→			.catch(() => null)
   422→	}
   423→
   424→	checkMailForPhishing(
   425→		mail: Mail,
   426→		links: Array<{
   427→			href: string
   428→			innerHTML: string
   429→		}>,
   430→	): Promise<boolean> {
   431→		return this.mailFacade.checkMailForPhishing(mail, links)
   432→	}
   433→
   434→	/**
   435→	 * Sends the given folder and all its descendants to the trash folder, removes any empty folders
   436→	 */
   437→	async trashFolderAndSubfolders(folder: MailFolder): Promise<void> {
   438→		const mailboxDetail = await this.getMailboxDetailsForMailListId(folder.mails)
   439→		if (mailboxDetail == null) {
   440→			return
   441→		}
   442→		let deletedFolder = await this.removeAllEmpty(mailboxDetail, folder)
   443→		if (!deletedFolder) {
   444→			const trash = assertSystemFolderOfType(mailboxDetail.folders, MailFolderType.TRASH)
   445→			return this.mailFacade.updateMailFolderParent(folder, trash._id)
   446→		}
   447→	}
   448→
   449→	/**
   450→	 * This is called when moving a folder to SPAM or TRASH, which do not allow empty folders (since only folders that contain mail are allowed)
   451→	 */
   452→	private async removeAllEmpty(mailboxDetail: MailboxDetail, folder: MailFolder): Promise<boolean> {
   453→		// sort descendants deepest first so that we can clean them up before checking their ancestors
   454→		const descendants = mailboxDetail.folders.getDescendantFoldersOfParent(folder._id).sort((l, r) => r.level - l.level)
   455→
   456→		// we completely delete empty folders
   457→		let someNonEmpty = false
   458→		// we don't update folder system quickly enough so we keep track of deleted folders here and consider them "empty" when all their children are here
   459→		const deleted = new Set<Id>()
   460→		for (const descendant of descendants) {
   461→			// Only load one mail, if there is even one we won't remove
   462→			if (
   463→				(await this.entityClient.loadRange(MailTypeRef, descendant.folder.mails, GENERATED_MAX_ID, 1, true)).length === 0 &&
   464→				mailboxDetail.folders.getCustomFoldersOfParent(descendant.folder._id).every((f) => deleted.has(getElementId(f)))
   465→			) {
   466→				deleted.add(getElementId(descendant.folder))
   467→				await this.finallyDeleteCustomMailFolder(descendant.folder)
   468→			} else {
   469→				someNonEmpty = true
   470→			}
   471→		}
   472→		// Only load one mail, if there is even one we won't remove
   473→		if (
   474→			(await this.entityClient.loadRange(MailTypeRef, folder.mails, GENERATED_MAX_ID, 1, true)).length === 0 &&
   475→			mailboxDetail.folders.getCustomFoldersOfParent(folder._id).every((f) => deleted.has(getElementId(f))) &&
   476→			!someNonEmpty
   477→		) {
   478→			await this.finallyDeleteCustomMailFolder(folder)
   479→			return true
   480→		} else {
   481→			return false
   482→		}
   483→	}
   484→
   485→	public async finallyDeleteCustomMailFolder(folder: MailFolder): Promise<void> {
   486→		if (folder.folderType !== MailFolderType.CUSTOM) {
   487→			throw new ProgrammingError("Cannot delete non-custom folder: " + String(folder._id))
   488→		}
   489→
   490→		return await this.mailFacade
   491→			.deleteFolder(folder._id)
   492→			.catch(ofClass(NotFoundError, () => console.log("mail folder already deleted")))
   493→			.catch(
   494→				ofClass(PreconditionFailedError, () => {
   495→					throw new UserError("operationStillActive_msg")
   496→				}),
   497→			)
   498→	}
   499→
   500→	async fixupCounterForMailList(listId: Id, unreadMails: number) {
   501→		const mailboxDetails = await this.getMailboxDetailsForMailListId(listId)
   502→		mailboxDetails && (await this.mailFacade.fixupCounterForMailList(mailboxDetails.mailGroup._id, listId, unreadMails))
   503→	}
   504→
   505→	async clearFolder(folder: MailFolder): Promise<void> {
   506→		await this.mailFacade.clearFolder(folder._id)
   507→	}
   508→
   509→	async unsubscribe(mail: Mail, recipient: string, headers: string[]) {
   510→		await this.mailFacade.unsubscribe(mail._id, recipient, headers)
