   513→	async getMailboxProperties(mailboxGroupRoot: MailboxGroupRoot): Promise<MailboxProperties> {
   514→		// MailboxProperties is an encrypted instance that is created lazily. When we create it the reference is automatically written to the MailboxGroupRoot.
   515→		// Unfortunately we will only get updated new MailboxGroupRoot with the next EntityUpdate.
   516→		// To prevent parallel creation attempts we do two things:
   517→		//  - we save the loading promise to avoid calling setup() twice in parallel
   518→		//  - we set mailboxProperties reference manually (we could save the id elsewhere but it's easier this way)
   519→
   520→		// If we are already loading/creating, just return it to avoid races
   521→		const existingPromise = this.mailboxPropertiesPromises.get(mailboxGroupRoot._id)
   522→		if (existingPromise) {
   523→			return existingPromise
   524→		}
   525→
   526→		const promise: Promise<MailboxProperties> = this.loadOrCreateMailboxProperties(mailboxGroupRoot)
   527→		this.mailboxPropertiesPromises.set(mailboxGroupRoot._id, promise)
   528→		return promise.finally(() => this.mailboxPropertiesPromises.delete(mailboxGroupRoot._id))
   529→	}
   530→
   531→	private async loadOrCreateMailboxProperties(mailboxGroupRoot: MailboxGroupRoot): Promise<MailboxProperties> {
   532→		if (!mailboxGroupRoot.mailboxProperties) {
   533→			mailboxGroupRoot.mailboxProperties = await this.entityClient
   534→				.setup(
   535→					null,
   536→					createMailboxProperties({
   537→						_ownerGroup: mailboxGroupRoot._ownerGroup,
   538→					}),
   539→				)
   540→				.catch(
   541→					ofClass(PreconditionFailedError, (e) => {
   542→						// We try to prevent race conditions but they can still happen with multiple clients trying ot create mailboxProperties at the same time.
   543→						// We send special precondition from the server with an existing id.
   544→						if (e.data && e.data.startsWith("exists:")) {
   545→							const existingId = e.data.substring("exists:".length)
   546→							console.log("mailboxProperties already exists", existingId)
   547→							return existingId
   548→						} else {
   549→							throw new ProgrammingError(`Could not create mailboxProperties, precondition: ${e.data}`)
   550→						}
   551→					}),
   552→				)
   553→		}
   554→		const mailboxProperties = await this.entityClient.load(MailboxPropertiesTypeRef, mailboxGroupRoot.mailboxProperties)
   555→		if (mailboxProperties.mailAddressProperties.length === 0) {
   556→			await this.migrateFromOldSenderName(mailboxGroupRoot, mailboxProperties)
   557→		}
   558→		return mailboxProperties
   559→	}
