   561→	/** If there was no sender name configured before take the user's name and assign it to all email addresses. */
   562→	private async migrateFromOldSenderName(mailboxGroupRoot: MailboxGroupRoot, mailboxProperties: MailboxProperties) {
   563→		const userGroupInfo = this.logins.getUserController().userGroupInfo
   564→		const legacySenderName = userGroupInfo.name
   565→		const mailboxDetails = await this.getMailboxDetailsForMailGroup(mailboxGroupRoot._id)
   566→		const mailAddresses = getEnabledMailAddressesWithUser(mailboxDetails, userGroupInfo)
   567→		for (const mailAddress of mailAddresses) {
   568→			mailboxProperties.mailAddressProperties.push(
   569→				createMailAddressProperties({
   570→					mailAddress,
   571→					senderName: legacySenderName,
   572→				}),
   573→			)
   574→		}
   575→		await this.entityClient.update(mailboxProperties)
   576→	}
