1→import type { EntityRestInterface } from "../worker/rest/EntityRestClient"
     2→import type { RootInstance } from "../entities/sys/TypeRefs.js"
     3→import { RootInstanceTypeRef } from "../entities/sys/TypeRefs.js"
     4→import { CUSTOM_MIN_ID, firstBiggerThanSecond, GENERATED_MIN_ID, getElementId, getLetId, RANGE_ITEM_LIMIT } from "./utils/EntityUtils"
     5→import { Type, ValueType } from "./EntityConstants"
     6→import { last, TypeRef } from "@tutao/tutanota-utils"
     7→import { resolveTypeReference } from "./EntityFunctions"
     8→import type { ElementEntity, ListElementEntity, SomeEntity } from "./EntityTypes"
     9→import { downcast } from "@tutao/tutanota-utils"
    10→import { EntityRestClientSetupOptions } from "../worker/rest/EntityRestClient"
    11→
    12→export class EntityClient {
    13→	_target: EntityRestInterface
    14→
    15→	constructor(target: EntityRestInterface) {
    16→		this._target = target
    17→	}
    18→
    19→	load<T extends SomeEntity>(typeRef: TypeRef<T>, id: PropertyType<T, "_id">, query?: Dict, extraHeaders?: Dict, ownerKey?: Aes128Key): Promise<T> {
    20→		return this._target.load(typeRef, id, query, extraHeaders, ownerKey)
    21→	}
    22→
    23→	async loadAll<T extends ListElementEntity>(typeRef: TypeRef<T>, listId: Id, start?: Id): Promise<T[]> {
    24→		const typeModel = await resolveTypeReference(typeRef)
    25→
    26→		if (!start) {
    27→			start = typeModel.values["_id"].type === ValueType.GeneratedId ? GENERATED_MIN_ID : CUSTOM_MIN_ID
    28→		}
    29→
    30→		const elements = await this.loadRange<T>(typeRef, listId, start, RANGE_ITEM_LIMIT, false)
    31→		if (elements.length === RANGE_ITEM_LIMIT) {
    32→			let lastElementId = getLetId(elements[elements.length - 1])[1]
    33→			const nextElements = await this.loadAll<T>(typeRef, listId, lastElementId)
    34→			return elements.concat(nextElements)
    35→		} else {
    36→			return elements
    37→		}
    38→	}
    39→
    40→	async loadReverseRangeBetween<T extends ListElementEntity>(
    41→		typeRef: TypeRef<T>,
    42→		listId: Id,
    43→		start: Id,
    44→		end: Id,
    45→		rangeItemLimit: number = RANGE_ITEM_LIMIT,
    46→	): Promise<{
    47→		elements: T[]
    48→		loadedCompletely: boolean
    49→	}> {
    50→		const typeModel = await resolveTypeReference(typeRef)
    51→		if (typeModel.type !== Type.ListElement) throw new Error("only ListElement types are permitted")
    52→		const loadedEntities = await this._target.loadRange<T>(typeRef, listId, start, rangeItemLimit, true)
    53→		const filteredEntities = loadedEntities.filter((entity) => firstBiggerThanSecond(getElementId(entity), end, typeModel))
    54→
    55→		if (filteredEntities.length === rangeItemLimit) {
    56→			const lastElementId = getElementId(filteredEntities[loadedEntities.length - 1])
    57→			const { elements: remainingEntities, loadedCompletely } = await this.loadReverseRangeBetween<T>(typeRef, listId, lastElementId, end, rangeItemLimit)
    58→			return {
    59→				elements: filteredEntities.concat(remainingEntities),
    60→				loadedCompletely,
    61→			}
    62→		} else {
    63→			return {
    64→				elements: filteredEntities,
    65→				loadedCompletely: wasReverseRangeCompletelyLoaded(rangeItemLimit, loadedEntities, filteredEntities),
    66→			}
    67→		}
    68→	}
    69→
    70→	loadRange<T extends ListElementEntity>(typeRef: TypeRef<T>, listId: Id, start: Id, count: number, reverse: boolean): Promise<T[]> {
    71→		return this._target.loadRange(typeRef, listId, start, count, reverse)
    72→	}
    73→
    74→	/**
    75→	 * load multiple does not guarantee order or completeness of returned elements.
    76→	 */
    77→	loadMultiple<T extends SomeEntity>(typeRef: TypeRef<T>, listId: Id | null, elementIds: Id[]): Promise<T[]> {
    78→		return this._target.loadMultiple(typeRef, listId, elementIds)
    79→	}
    80→
    81→	setup<T extends SomeEntity>(listId: Id | null, instance: T, extraHeaders?: Dict, options?: EntityRestClientSetupOptions): Promise<Id> {
    82→		return this._target.setup(listId, instance, extraHeaders, options)
    83→	}
    84→
    85→	setupMultipleEntities<T extends SomeEntity>(listId: Id | null, instances: Array<T>): Promise<Array<Id>> {
    86→		return this._target.setupMultiple(listId, instances)
    87→	}
    88→
    89→	update<T extends SomeEntity>(instance: T, ownerKey?: Aes128Key): Promise<void> {
    90→		return this._target.update(instance, ownerKey)
    91→	}
    92→
    93→	erase<T extends SomeEntity>(instance: T): Promise<void> {
    94→		return this._target.erase(instance)
    95→	}
    96→
    97→	async loadRoot<T extends ElementEntity>(typeRef: TypeRef<T>, groupId: Id): Promise<T> {
    98→		const typeModel = await resolveTypeReference(typeRef)
    99→		const rootId = [groupId, typeModel.rootId] as const
   100→		const root = await this.load<RootInstance>(RootInstanceTypeRef, rootId)
   101→		return this.load<T>(typeRef, downcast(root.reference))
   102→	}
   103→}
   104→
   105→function wasReverseRangeCompletelyLoaded<T extends ListElementEntity>(rangeItemLimit: number, loadedEntities: Array<T>, filteredEntities: Array<T>): boolean {
   106→	if (loadedEntities.length < rangeItemLimit) {
   107→		const lastLoaded = last(loadedEntities)
   108→		const lastFiltered = last(filteredEntities)
   109→
   110→		if (!lastLoaded) {
   111→			return true
   112→		}
   113→
   114→		return lastLoaded === lastFiltered
   115→	}
   116→
   117→	return false
   118→}
