		private readonly instanceMapper: InstanceMapper,
		private readonly blobAccessTokenFacade: BlobAccessTokenFacade,
	) {}

	async load<T extends SomeEntity>(
		typeRef: TypeRef<T>,
		id: PropertyType<T, "_id">,
		queryParameters?: Dict,
		extraHeaders?: Dict,
		ownerKey?: Aes128Key,
	): Promise<T> {
