   260→		return getDefaultSender(logins, mailboxDetails)
   261→	} else {
   262→		return getGroupInfoDisplayName(assertNotNull(mailboxDetails.mailGroupInfo, "mailboxDetails without mailGroupInfo?"))
   263→	}
