   267→	insertImage(srcAttr: string, attrs?: Record<string, string>): HTMLElement
   268→}
   269→
   270→/**
   271→ * Check if all mails in the selection are drafts. If there are mixed drafts and non-drafts or the array is empty, return true.
   272→ * @param mails
   273→ */
   274→export function emptyOrContainsDraftsAndNonDrafts(mails: ReadonlyArray<Mail>): boolean {
   275→	return mails.length === 0 || (mails.some((mail) => mail.state === MailState.DRAFT) && mails.some((mail) => mail.state !== MailState.DRAFT))
   276→}
