   283→}
   284→
   285→export function getTemplateLanguages(sortedLanguages: Array<Language>, entityClient: EntityClient, loginController: LoginController): Promise<Array<Language>> {
   286→	return loginController
   287→		.getUserController()
   288→		.loadCustomer()
