   292→		})
   293→		.catch(() => [])
   294→}
   295→
   296→export function conversationTypeString(conversationType: ConversationType): string {
   297→	let key: TranslationKey
   298→
   299→	switch (conversationType) {
   300→		case ConversationType.NEW:
   301→			key = "newMail_action"
   302→			break
   303→
   304→		case ConversationType.REPLY:
   305→			key = "reply_action"
   306→			break
   307→
   308→		case ConversationType.FORWARD:
   309→			key = "forward_action"
   310→			break
   311→
   312→		default:
   313→			key = "emptyString_msg"
   314→	}
   315→
   316→	return lang.get(key)
   317→}
