			ccRecipients: [],
			bccRecipients: [],
			replyTos: [],
			attachments: [],
			firstRecipient: null,
			recipientCount: "0",
			mailDetails: ["list1", "mailDetails123"],
			headers: null,
			conversationEntry: null,
		}) as Mail

