		// 1. The entity IS loaded (no exception from loadMultiple itself)
		expect(mailDetailsBlobs).toHaveLength(1)

		// 2. But the entity doesn't have the session key information needed for decryption
		const mailDetailsBlob = mailDetailsBlobs[0]
		expect(mailDetailsBlob._id).toEqual(["list1", "mailDetails123"])

		// 3. The crucial issue: the entity doesn't have _ownerEncSessionKey
		// In real code, when CryptoFacade tries to decrypt this, it will fail
		// because the session key from the parent mail is NOT propagated
		expect(mailDetailsBlob._ownerEncSessionKey).toBeUndefined()

		// 4. The parent mail HAS the session key
		expect(mail._ownerEncSessionKey).toBe("encryptedMailSessionKey")

		// 5. But there's no way for the decryption code to access it
		// This is the ROOT CAUSE of the bug
	})

	test("demonstrates that loadMultiple cannot receive session key from parent entity", async () => {
		const mockRestClient = new BuggyEntityRestClientMock()
		const entityClient = new EntityClient(mockRestClient)

		// This test shows that the EntityClient.loadMultiple signature doesn't
		// support passing a session key or ownerKey parameter

		// The method signature is:
		// loadMultiple<T extends SomeEntity>(typeRef: TypeRef<T>, listId: Id | null, elementIds: Id[]): Promise<T[]>

		// There's no parameter for:
		// - ownerKey (unlike load and update methods which have this parameter)
		// - sessionKey (no such parameter exists)

		// This is the structural problem that makes it impossible to pass the
		// parent mail's session key to loadMultiple

		const emailDetailsIds = ["mailDetails123"]

		// No way to pass the mail's session key here:
		const mailDetails = await entityClient.loadMultiple(
